// src/components/Home.js
import React, { useState } from "react";
import "Home.css"; // Импортируем CSS файл

// Пример иерархической структуры директорий и файлов
const directories = [
    {
        name: "Documents",
        subdirectories: [
            {
                name: "Work",
                files: ["report.docx", "budget.xlsx"],
            },
            {
                name: "Personal",
                files: ["letter.txt", "cv.pdf"],
            },
        ],
    },
    {
        name: "Downloads",
        subdirectories: [
            {
                name: "Images",
                files: ["photo1.jpg", "photo2.png"],
            },
            {
                name: "Videos",
                files: ["video1.mp4", "video2.mkv"],
            },
        ],
    },
];

const Home = () => {
    const [selectedDir, setSelectedDir] = useState(null);
    const [selectedFile, setSelectedFile] = useState(null);

    const handleDirectorySelect = (dir) => {
        setSelectedDir(dir);
        setSelectedFile(null);
    };

    const handleFileSelect = (file) => {
        setSelectedFile(file);
    };

    return (
        <div className="container">
            {/* Боковой раздел */}
            <div className="sidebar">
                <h3>Директории</h3>
                <ul className="dirList">
                    {directories.map((dir, idx) => (
                        <li key={idx}>
                            <button
                                className="button"
                                onClick={() => handleDirectorySelect(dir)}
                            >
                                {dir.name}
                            </button>
                            {selectedDir === dir && (
                                <ul className="subDirList">
                                    {dir.subdirectories.map(
                                        (subDir, subIdx) => (
                                            <li key={subIdx}>
                                                <button
                                                    className="button"
                                                    onClick={() =>
                                                        handleDirectorySelect(
                                                            subDir
                                                        )
                                                    }
                                                >
                                                    {subDir.name}
                                                </button>
                                            </li>
                                        )
                                    )}
                                </ul>
                            )}
                        </li>
                    ))}
                </ul>
            </div>

            {/* Основной раздел */}
            <div className="mainContent">
                {selectedDir ? (
                    <>
                        <h3>Файлы в {selectedDir.name}</h3>
                        <ul className="fileList">
                            {selectedDir.subdirectories &&
                                selectedDir.subdirectories.map(
                                    (subDir, idx) => (
                                        <div key={idx}>
                                            <h4>{subDir.name}</h4>
                                            <ul>
                                                {subDir.files.map(
                                                    (file, fileIdx) => (
                                                        <li key={fileIdx}>
                                                            <button
                                                                className="button"
                                                                onClick={() =>
                                                                    handleFileSelect(
                                                                        file
                                                                    )
                                                                }
                                                            >
                                                                {file}
                                                            </button>
                                                        </li>
                                                    )
                                                )}
                                            </ul>
                                        </div>
                                    )
                                )}
                        </ul>
                    </>
                ) : (
                    <p>Выберите директорию для отображения файлов.</p>
                )}
            </div>

            {/* Нижний раздел */}
            <div className="footer">
                {selectedFile ? (
                    <div>
                        <h4>Содержимое файла: {selectedFile}</h4>
                        <p>Здесь будет отображаться содержимое файла...</p>
                    </div>
                ) : (
                    <p>Выберите файл для просмотра содержимого.</p>
                )}
            </div>
        </div>
    );
};

export default Home;
